8.query:
fetch spans
| filter request.is_root_span == true
| filter isNotNull(endpoint.name)
| filter dt.internal.is_failed == true or request.is_failed == true
| fieldsAdd service = entityName(dt.entity.service)
| filter in($Service , "ALL") OR in(service, $Service)
| fieldsAdd timestamp = start_time
//| fieldsAdd ResponseCode = toLong(http.response.status_code)
//| filter ResponseCode >= 500 and ResponseCode < 600 
| makeTimeSeries Errors = count(), by:{service}

50.query:
fetch dt.davis.problems
| sort timestamp desc
| expand affected_entity_ids
| lookup [fetch dt.entity.application | fields name=entity.name, id=id, mz=managementZones], sourceField:affected_entity_ids, lookupField:id, prefix:"lookup.affected.entity.application"
| lookup [fetch dt.entity.mobile_application | fields name=entity.name, id=id, mz=managementZones], sourceField:affected_entity_ids, lookupField:id, prefix:"lookup.affected.entity.mobile"
| lookup [fetch dt.entity.custom_application | fields name=entity.name, id=id, mz=managementZones], sourceField:affected_entity_ids, lookupField:id, prefix:"lookup.affected.entity.custom"
| lookup [fetch dt.entity.synthetic_test | fields name=entity.name, id=id, mz=managementZones], sourceField:affected_entity_ids, lookupField:id, prefix:"lookup.affected.entity.synthetictest"
| lookup [fetch dt.entity.http_check | fields name=entity.name, id=id, mz=managementZones], sourceField:affected_entity_ids, lookupField:id, prefix:"lookup.affected.entity.httpcheck"
| lookup [fetch dt.entity.process_group | fields name=entity.name, id=id, mz=managementZones], sourceField:affected_entity_ids, lookupField:id, prefix:"lookup.affected.entity.pg"
| lookup [fetch dt.entity.service | fields name=entity.name, id=id, mz=managementZones], sourceField:affected_entity_ids, lookupField:id, prefix:"lookup.affected.entity.service"
| lookup [fetch dt.entity.host | fields name=entity.name, id=id, mz=managementZones], sourceField:affected_entity_ids, lookupField:id, prefix:"lookup.affected.entity.host"

// First Summarzation Start - Group Probem Events by Problem ID
| summarize {startTime = takeFirst(event.start),
            endTime = takeFirst(event.end),
            problemClosedDuration = takeFirst(resolved_problem_duration),
            status = takeFirst(event.status),
            event.name = takeFirst(event.name),
            severityLevel = takeFirst(event.category),
            affected = takeFirst(affected_entity_ids),
            rootCause = takeFirst(root_cause_entity_id),
            dt.davis.is_duplicate = takeFirst(dt.davis.is_duplicate),
            event.id = takeFirst(event.id)}, 
            by:{display_id}
| filter `dt.davis.is_duplicate` == false
// First Summarzation End - Group Probem Events by Problem ID

